INSERT INTO users (name, pin_hash, token, state) VALUES ('grammat', '', '80b93684-0cb5-488c-be39-cb1721ee0ace', '{"recipes":[{"id":"kottfarssas","title":"Köttfärssås","portions":6,"course":"huvudratt","source":"","ingredients":[{"name":"nötfärs","amount":800,"unit":"g","cat":"kött"},{"name":"gul lök","amount":220,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"morot","amount":240,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"stjälkselleri","amount":80,"unit":"g","count":2,"countUnit":"stjälkar","cat":"grönt"},{"name":"vitlök","amount":20,"unit":"g","count":4,"countUnit":"klyftor","cat":"grönt"},{"name":"olivolja","amount":100,"unit":"ml","cat":"skafferi"},{"name":"tomatpuré","amount":90,"unit":"ml","cat":"skafferi"},{"name":"rött vin (eller vatten)","amount":200,"unit":"ml","cat":"övrigt"},{"name":"krossade tomater","amount":800,"unit":"g","cat":"skafferi"},{"name":"torkad oregano","amount":3,"unit":"g","cat":"skafferi"},{"name":"torkad timjan","amount":2,"unit":"g","cat":"skafferi"},{"name":"lagerblad","amount":1,"unit":"g","count":2,"countUnit":"st","cat":"skafferi"},{"name":"salt","amount":12,"unit":"g","cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"pasta (till servering)","amount":480,"unit":"g","cat":"skafferi"}],"steps":["Finhacka lök, morot och selleri så fint du kan. Fräs mjukt i olivoljan utan att det tar färg.","Tryck till vitlöksklyftorna med knivbladet, finhacka och låt fräsa med i någon minut.","Tillsätt köttfärsen lite i taget så att den bryns och inte kokar. Tillsätt tomatpurén och fräs någon minut till.","Häll i vinet (eller vattnet) och låt koka upp snabbt.","Tillsätt krossade tomater, oregano, timjan och lagerblad. Salta och peppra. Låt puttra under lock i minst 20 minuter, gärna längre.","Servera med nykokt pasta."]},{"id":"kebab","title":"Kebab i långpanna","portions":6,"course":"huvudratt","source":"https://zeinaskitchen.se/kafta-kottfarskebab-i-langpanna/","ingredients":[{"name":"köttfärs","amount":1000,"unit":"g","group":"Kebaben","cat":"kött"},{"name":"rödlök","amount":80,"unit":"g","count":1,"countUnit":"st","group":"Kebaben","cat":"grönt"},{"name":"persilja","amount":40,"unit":"g","count":1,"countUnit":"bunt","group":"Kebaben","cat":"grönt"},{"name":"vitlök","amount":5,"unit":"g","count":1,"countUnit":"klyftor","group":"Kebaben","cat":"grönt"},{"name":"gurkmeja","amount":3,"unit":"g","group":"Kebaben","cat":"skafferi"},{"name":"kaftakrydda (eller 7 kryddor)","amount":4,"unit":"g","group":"Kebaben","cat":"skafferi"},{"name":"salt","amount":6,"unit":"g","group":"Kebaben","cat":"skafferi"},{"name":"svartpeppar","amount":3,"unit":"g","group":"Kebaben","cat":"skafferi"},{"name":"rödlök","amount":200,"unit":"g","count":2,"countUnit":"st","group":"Garnering","cat":"grönt"},{"name":"sivri (turkisk paprika) eller grön paprika","amount":150,"unit":"g","group":"Garnering","cat":"grönt"},{"name":"tomat","amount":360,"unit":"g","count":3,"countUnit":"st","group":"Garnering","cat":"grönt"},{"name":"olivolja","amount":70,"unit":"ml","group":"Garnering","cat":"skafferi"},{"name":"sumak (eller citron)","amount":10,"unit":"g","group":"Garnering","cat":"skafferi"}],"steps":["Blanda alla ingredienser till kebaben. Blanda inte färsen mer än nödvändigt, då trådar den sig och blir seg.","Platta ut köttet jämnt i en långpanna, ca 30×40 cm. Skär ut jämnstora kebabbitar.","Skär rödlöken i klyftor, gör ett kryss på tomaterna och lägg dem över färsen tillsammans med sivri eller paprikaklyftor.","Värm ugnen till 275 grader, gärna med grillfunktion. Ringla olivolja över allt på plåten och strö på sumak.","Grilla mitt i ugnen ca 15 minuter. Servera genast med sallad, pommes, ris eller bulgur."]},{"id":"lovbiff-teriyaki","title":"Lövbiff teriyaki med pak choi","portions":8,"course":"huvudratt","source":"https://www.ica.se/recept/lovbiff-teriyaki-med-pak-choi-och-lime-719793/","ingredients":[{"name":"ris (gärna jasmin)","amount":500,"unit":"g","cat":"skafferi"},{"name":"japansk soja","amount":200,"unit":"ml","group":"Sås","cat":"skafferi"},{"name":"vatten","amount":100,"unit":"ml","group":"Sås","skipList":true,"cat":"övrigt"},{"name":"honung (eller strösocker)","amount":100,"unit":"ml","group":"Sås","cat":"skafferi"},{"name":"färsk ingefära","amount":30,"unit":"g","group":"Sås","cat":"grönt"},{"name":"vitlök","amount":10,"unit":"g","count":2,"countUnit":"klyftor","group":"Sås","cat":"grönt"},{"name":"majsstärkelse","amount":6,"unit":"g","group":"Sås","cat":"skafferi"},{"name":"sambal oelek","amount":20,"unit":"ml","group":"Grönsaker","cat":"skafferi"},{"name":"lime","amount":130,"unit":"g","count":2,"countUnit":"st","group":"Grönsaker","cat":"grönt"},{"name":"olja","amount":30,"unit":"ml","group":"Grönsaker","cat":"skafferi"},{"name":"salt","toTaste":true,"group":"Grönsaker","cat":"skafferi"},{"name":"stjälkselleri","amount":450,"unit":"g","count":1,"countUnit":"förp","group":"Grönsaker","cat":"grönt"},{"name":"pak choi","amount":500,"unit":"g","group":"Grönsaker","cat":"grönt"},{"name":"lövbiff","amount":1000,"unit":"g","group":"Kött","cat":"kött"},{"name":"olja","amount":30,"unit":"ml","group":"Kött","cat":"skafferi"},{"name":"sesamfrön","amount":20,"unit":"g","group":"Kött","cat":"skafferi"}],"steps":["Koka riset enligt anvisningen på förpackningen.","Sås: blanda alla ingredienser i en kastrull. Koka såsen 3–5 minuter under omrörning.","Grönsaker: blanda sambal oelek, pressad limesaft och olja i en skål. Smaka av med salt. Ansa och strimla selleri och pak choi, vänd ner grönsakerna.","Strimla köttet. Stek det i oljan i omgångar i en het stekpanna tills det fått fin färg.","Häll på såsen och koka några minuter. Strö sesamfrön över köttet.","Servera köttet med ris och grönsaker."]},{"id":"veg-lasagne","title":"Vegetarisk lasagne","portions":8,"course":"huvudratt","source":"https://undertian.com/recept/billig-vegetarisk-lasagne/","ingredients":[{"name":"gul lök","amount":220,"unit":"g","count":2,"countUnit":"st","group":"Lins- och tomatsås","cat":"grönt"},{"name":"röda linser (torkade)","amount":340,"unit":"g","group":"Lins- och tomatsås","cat":"skafferi"},{"name":"krossade tomater","amount":800,"unit":"g","group":"Lins- och tomatsås","cat":"skafferi"},{"name":"vatten","amount":600,"unit":"ml","group":"Lins- och tomatsås","skipList":true,"cat":"övrigt"},{"name":"morot","amount":480,"unit":"g","count":4,"countUnit":"st","group":"Lins- och tomatsås","cat":"grönt"},{"name":"grönsaksbuljongtärning","amount":22,"unit":"g","count":2,"countUnit":"st","group":"Lins- och tomatsås","cat":"skafferi"},{"name":"tomatpuré","amount":30,"unit":"ml","group":"Lins- och tomatsås","cat":"skafferi"},{"name":"vitlök","amount":10,"unit":"g","count":2,"countUnit":"klyftor","group":"Lins- och tomatsås","cat":"grönt"},{"name":"torkade örter (basilika/oregano/timjan)","amount":6,"unit":"g","group":"Lins- och tomatsås","cat":"skafferi"},{"name":"salt","toTaste":true,"group":"Lins- och tomatsås","cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"group":"Lins- och tomatsås","cat":"skafferi"},{"name":"olja att steka i","toTaste":true,"group":"Lins- och tomatsås","cat":"skafferi"},{"name":"crème fraiche","amount":500,"unit":"ml","group":"Ostsås","cat":"mejeri"},{"name":"riven ost","amount":80,"unit":"g","group":"Ostsås","cat":"mejeri"},{"name":"lasagneplattor","amount":500,"unit":"g","group":"Montering","cat":"skafferi"},{"name":"riven ost","amount":50,"unit":"g","group":"Montering","cat":"mejeri"}],"steps":["Hacka löken fint. Värm olja i en stor kastrull och stek löken tills den är blank.","Skölj linserna i kallt vatten. Lägg dem i kastrullen och slå på krossade tomater och vatten. Riv morötterna och lägg i. Tillsätt buljongtärning och tomatpuré. Koka under lock ca 10 minuter på medelsvag värme, rör om då och då.","Sätt ugnen på 225 grader.","Späd såsen med mer vatten om det behövs, den ska vara tjock men inte rinnig. Pressa i vitlöken och smaka av med salt, peppar och örterna.","Ostsås: värm crème fraiche i en kastrull och blanda i den rivna osten. Låt osten smälta, såsen ska inte koka. Salta och peppra.","Smörj en ugnsform. Lägg tomatsås i botten och varva med lasagneplattor, tomatsås och ostsås tills plattorna är slut. Avsluta med ostsås och strö ost överst.","Grädda mitt i ugnen ca 20 minuter, håll koll så lasagnen inte bränns.","Servera med en sallad."]},{"id":"broccolisoppa","title":"Broccolisoppa","portions":6,"course":"huvudratt","source":"https://www.allrecipes.com/recipe/13313/best-cream-of-broccoli-soup/","ingredients":[{"name":"smör","amount":55,"unit":"g","cat":"mejeri"},{"name":"gul lök","amount":110,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"stjälkselleri","amount":40,"unit":"g","count":1,"countUnit":"stjälkar","cat":"grönt"},{"name":"kycklingbuljong","amount":720,"unit":"ml","cat":"skafferi"},{"name":"broccoli","amount":700,"unit":"g","cat":"grönt"},{"name":"vetemjöl","amount":25,"unit":"g","cat":"skafferi"},{"name":"mjölk","amount":480,"unit":"ml","cat":"mejeri"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"}],"steps":["Smält ungefär en tredjedel av smöret i en kastrull. Fräs lök och selleri tills de mjuknat.","Tillsätt broccoli och buljong. Låt sjuda under lock i 10 minuter.","Mixa soppan slät med stavmixer, eller i mixer i omgångar.","Smält resten av smöret i en liten kastrull. Rör i mjölet och späd med mjölken. Rör tills det tjocknar och bubblar, blanda sedan ner i soppan.","Smaka av med svartpeppar."]},{"id":"loomisar","title":"Haloumipasta","portions":6,"course":"huvudratt","source":"","ingredients":[{"name":"halloumi","amount":200,"unit":"g","count":1,"countUnit":"pkt","cat":"mejeri"},{"name":"rödpesto","amount":95,"unit":"g","count":0.5,"countUnit":"burk","cat":"skafferi"},{"name":"svarta oliver (urkärnade)","amount":150,"unit":"g","count":1,"countUnit":"burk","cat":"skafferi"},{"name":"tomat","amount":720,"unit":"g","count":6,"countUnit":"st","cat":"grönt"},{"name":"rödlök","amount":100,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"vitlök","toTaste":true,"cat":"grönt"},{"name":"pasta (till servering)","amount":480,"unit":"g","cat":"skafferi"}],"steps":["Hacka lök, vitlök och tomater.","Skär halloumi i kuber, halvera oliver och stek tillsammans.","Stek lök, vitlök och sedan tomater.","Blanda ihop med rödpesto och låt puttra ett tag.","Rör ihop med pasta och servera."]},{"id":"markus-salsiccia-fankal","title":"Markus färsk salsiccia med fänkål","portions":2,"course":"huvudratt","source":"https://youtu.be/9T5Uh4wKa0Q","ingredients":[{"name":"färsk salsiccia","amount":320,"unit":"g","count":1,"countUnit":"pkt","cat":"kött"},{"name":"röd chili","amount":15,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"gul lök","amount":55,"unit":"g","count":0.5,"countUnit":"st","cat":"grönt"},{"name":"vitlök","amount":5,"unit":"g","count":1,"countUnit":"klyfta","cat":"grönt"},{"name":"tomat","amount":240,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"olivolja","toTaste":true,"cat":"skafferi"},{"name":"torrt vitt vin","amount":100,"unit":"ml","cat":"övrigt"},{"name":"fänkålsfrön","amount":8,"unit":"g","cat":"skafferi"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"persilja","toTaste":true,"cat":"grönt"},{"name":"pecorinoost (till servering)","toTaste":true,"cat":"mejeri"}],"steps":[]},{"id":"marockansk-kyckling","title":"Marockansk kyckling med sötpotatismos","portions":4,"course":"huvudratt","source":"https://www.bbcgoodfood.com/recipes/moroccan-chicken-sweet-potato-mash","ingredients":[{"name":"sötpotatis","amount":1000,"unit":"g","cat":"grönt"},{"name":"ras el hanout (eller kanel och spiskummin)","amount":10,"unit":"g","cat":"skafferi"},{"name":"kycklingfilé","amount":600,"unit":"g","count":4,"countUnit":"st","cat":"kött"},{"name":"olivolja","amount":30,"unit":"ml","cat":"skafferi"},{"name":"gul lök","amount":110,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"vitlök","amount":5,"unit":"g","count":1,"countUnit":"klyfta","cat":"grönt"},{"name":"kycklingbuljong","amount":200,"unit":"ml","cat":"skafferi"},{"name":"honung","amount":10,"unit":"ml","cat":"skafferi"},{"name":"citron","amount":50,"unit":"g","count":0.5,"countUnit":"st","cat":"grönt"},{"name":"gröna oliver","amount":50,"unit":"g","cat":"skafferi"},{"name":"koriander","amount":20,"unit":"g","cat":"grönt"}],"steps":["Koka sötpotatisen i saltat vatten i 15 minuter eller tills mör. Blanda ras el hanout med salt och peppar och gnid in på kycklingen. Bryn kycklingen i olja i en stekpanna, ca 3 minuter per sida, tills gyllene.","Lyft ur kycklingen. Fräs lök och vitlök i 5 minuter tills mjuka. Tillsätt buljong, honung, citronjuice och oliver, lägg tillbaka kycklingen och låt sjuda 10 minuter tills såsen tjocknat och kycklingen är genomstekt.","Mosa sötpotatisen med lite olja, salta och peppra. Skiva kycklingen och rör ner koriandern i såsen. Servera kycklingen och såsen på moset."]},{"id":"rakpasta","title":"Räkpasta med chili och vitlök","portions":4,"course":"huvudratt","source":"https://mittkok.expressen.se/recept/spaghetti-med-rakor-chili-och-vitlok/","ingredients":[{"name":"spagetti","amount":400,"unit":"g","cat":"skafferi"},{"name":"räkor (skalade)","amount":300,"unit":"g","cat":"kött"},{"name":"olivolja","amount":100,"unit":"ml","cat":"skafferi"},{"name":"vitlök","amount":15,"unit":"g","count":3,"countUnit":"klyftor","cat":"grönt"},{"name":"röd chili","amount":15,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"miniplommontomater","amount":200,"unit":"g","cat":"grönt"},{"name":"salt","amount":3,"unit":"g","cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"citron","amount":33,"unit":"g","count":0.5,"countUnit":"st","cat":"grönt"},{"name":"rucolasallad","amount":70,"unit":"g","cat":"grönt"},{"name":"parmesanost","amount":100,"unit":"g","cat":"mejeri"}],"steps":[]},{"id":"chili-con-carne","title":"Chili con carne","portions":4,"course":"huvudratt","source":"","ingredients":[{"name":"nötfärs","amount":500,"unit":"g","cat":"kött"},{"name":"gul lök","amount":220,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"vitlök","amount":10,"unit":"g","count":2,"countUnit":"klyftor","cat":"grönt"},{"name":"röd chili","amount":15,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"grön paprika","amount":150,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"tomatpuré","amount":30,"unit":"ml","cat":"skafferi"},{"name":"hela tomater (burk)","amount":400,"unit":"g","count":1,"countUnit":"burk","cat":"skafferi"},{"name":"vatten","amount":400,"unit":"ml","skipList":true,"cat":"övrigt"},{"name":"kidneybönor (avrunna)","amount":480,"unit":"g","count":1,"countUnit":"pkt","cat":"skafferi"},{"name":"torkad timjan","amount":2,"unit":"g","cat":"skafferi"},{"name":"torkad oregano","amount":3,"unit":"g","cat":"skafferi"},{"name":"malen spiskummin","amount":4,"unit":"g","cat":"skafferi"},{"name":"rökt paprikapulver","amount":2,"unit":"g","cat":"skafferi"},{"name":"kakao","amount":5,"unit":"g","cat":"skafferi"},{"name":"bbq-sås","amount":30,"unit":"ml","cat":"skafferi"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"koriander","amount":20,"unit":"g","count":1,"countUnit":"kruka","cat":"grönt"},{"name":"olivolja","toTaste":true,"cat":"skafferi"},{"name":"ris (till servering)","toTaste":true,"cat":"skafferi"}],"steps":[]},{"id":"kycklingsallad-tex-mex","title":"Kycklingsallad tex mex","portions":4,"course":"huvudratt","source":"https://www.tasteline.com/recept/texmexsallad-med-kyckling/","ingredients":[{"name":"kyckling","amount":800,"unit":"g","cat":"kött"},{"name":"smör","amount":30,"unit":"g","cat":"mejeri"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"texmexkrydda","amount":12,"unit":"g","cat":"skafferi"},{"name":"röd paprika","amount":300,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"avokado","amount":600,"unit":"g","count":4,"countUnit":"st","cat":"grönt"},{"name":"tomat","amount":480,"unit":"g","count":4,"countUnit":"st","cat":"grönt"},{"name":"rödlök","amount":160,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"majs (fryst, tinad)","amount":170,"unit":"g","cat":"fryst"},{"name":"svarta bönor (kokta)","amount":340,"unit":"g","cat":"skafferi"},{"name":"blandad sallad","amount":200,"unit":"g","count":2,"countUnit":"påse","cat":"grönt"},{"name":"salsa (texmex)","amount":300,"unit":"ml","cat":"skafferi"},{"name":"gräddfil","amount":200,"unit":"ml","cat":"mejeri"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"}],"steps":["Skär kycklingen i små bitar, stek i smör. Salta och peppra och krydda med texmexblandning, rör runt och lägg sedan i en skål. Låt svalna lite.","Skär paprika, avokado och tomat i bitar.","Finhacka löken. Lägg allt i skålen med kyckling. Skölj bönorna och tillsätt dessa. Tillsätt sallad och majs. Blanda runt och servera med salsa och gräddfil."]},{"id":"teriyaki-biff","title":"Teriyaki biff","portions":8,"course":"huvudratt","source":"https://www.kokaihop.se/recept/biff-teriyaki","ingredients":[{"name":"lövbiff","amount":800,"unit":"g","cat":"kött"},{"name":"morot","amount":480,"unit":"g","count":4,"countUnit":"st","cat":"grönt"},{"name":"gul lök","amount":220,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"broccoli","amount":800,"unit":"g","count":2,"countUnit":"huvuden","cat":"grönt"},{"name":"olja","amount":30,"unit":"ml","cat":"skafferi"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"teriyakisås","amount":200,"unit":"ml","cat":"skafferi"},{"name":"kinesisk soja","amount":60,"unit":"ml","cat":"skafferi"},{"name":"sambal oelek","amount":10,"unit":"ml","cat":"skafferi"},{"name":"grädde (kokbar)","amount":500,"unit":"ml","cat":"mejeri"}],"steps":["Skala och skiva löken.","Skala morötterna och skär tunna skivor på snedden.","Dela broccolin i små bitar.","Fräs köttet lite i taget i stor stekpanna eller wokpanna.","Ta upp allt köttet och fräs grönsakerna under omrörning tills de börjar mjukna.","Lägg tillbaka köttet och salta, men inte för mycket.","Tillsätt teriyakisåsen, sojan, sambal oelek och grädden och låt småkoka några minuter."]},{"id":"gazpacho","title":"Gazpacho","portions":4,"course":"forratt","source":"https://youtu.be/OZkE_d2CwBw","ingredients":[{"name":"gurka","amount":400,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"plommontomater","amount":490,"unit":"g","count":7,"countUnit":"st","cat":"grönt"},{"name":"röd paprika","amount":150,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"grön paprika","amount":150,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"silverlök","amount":20,"unit":"g","cat":"grönt"},{"name":"vitlök","amount":2.5,"unit":"g","count":0.5,"countUnit":"klyfta","cat":"grönt"},{"name":"olivolja","amount":60,"unit":"ml","cat":"skafferi"},{"name":"sherryvinäger","amount":20,"unit":"ml","cat":"skafferi"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"strösocker","toTaste":true,"cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"vitt bröd (till krutonger)","toTaste":true,"cat":"skafferi"}],"steps":[]},{"id":"sommarsmorgastarta","title":"Sommarsmörgåstårta","portions":8,"course":"huvudratt","source":"https://www.niiinis.se/2020/06/19/sommarsmorgastarta-med-farskpotatis/","ingredients":[{"name":"jubileumskaka (runt rågbröd)","amount":1200,"unit":"g","count":2,"countUnit":"st","cat":"skafferi"},{"name":"crème fraiche","amount":500,"unit":"ml","cat":"mejeri"},{"name":"färskost","amount":300,"unit":"g","cat":"mejeri"},{"name":"rödlök","amount":110,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"dill","amount":25,"unit":"g","count":1,"countUnit":"bunt","cat":"grönt"},{"name":"cayennepeppar","amount":2,"unit":"g","cat":"skafferi"},{"name":"honung","amount":30,"unit":"ml","cat":"skafferi"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"ägg","amount":180,"unit":"g","count":3,"countUnit":"st","cat":"mejeri"},{"name":"handskalade räkor","amount":200,"unit":"g","cat":"kött"},{"name":"färskpotatis","amount":400,"unit":"g","count":4,"countUnit":"st","cat":"grönt"},{"name":"handskalade räkor","amount":300,"unit":"g","group":"Garnering","cat":"kött"},{"name":"ägg","amount":180,"unit":"g","count":3,"countUnit":"st","group":"Garnering","cat":"mejeri"},{"name":"färskpotatis","amount":400,"unit":"g","count":4,"countUnit":"st","group":"Garnering","cat":"grönt"},{"name":"salladslök","amount":15,"unit":"g","count":0.5,"countUnit":"st","group":"Garnering","cat":"grönt"}],"steps":["Koka potatisen (till både fyllning och garnering), låt sedan svalna.","Vispa crème fraiche fluffig och blanda med färskost, hackad rödlök, hackad dill, cayennepeppar och honung. Salta och peppra.","Lägg ut ett bröd på ett stort fat. Bred ut hälften av fyllningen. Skiva färskpotatis och lägg på, dela äggen i klyftor och lägg på dem också. Toppa med lite räkor.","Lägg på det andra brödet. Bred ut resten av fyllningen och toppa snyggt med garneringens räkor, ägg, potatis och salladslök. Låt stå kallt någon timme innan servering."]},{"id":"grillsasen","title":"Grillsåsen","portions":6,"course":"sas","source":"","ingredients":[{"name":"crème fraiche","amount":300,"unit":"g","count":1,"countUnit":"burk","cat":"mejeri"},{"name":"mango chutney","amount":38,"unit":"ml","cat":"skafferi"},{"name":"vitlök","amount":5,"unit":"g","count":1,"countUnit":"klyfta","cat":"grönt"},{"name":"ingefära (malen)","amount":1,"unit":"g","cat":"skafferi"},{"name":"curry","amount":1,"unit":"g","cat":"skafferi"},{"name":"cayennepeppar","toTaste":true,"cat":"skafferi"},{"name":"rödlök","amount":40,"unit":"g","count":1,"countUnit":"st","cat":"grönt"}],"steps":["Blanda crème fraiche, mango chutney, pressad vitlök, ingefära, curry, cayennepeppar och finhackad rödlök.","Smaka av och låt gärna stå kallt en stund innan servering."]},{"id":"pasta-kraftstjartar","title":"Pastasås med kräftstjärtar","portions":3,"course":"huvudratt","source":"https://www.recepten.se/recept/pasta_kraeftstjaertar.html","ingredients":[{"name":"bandspagetti","amount":300,"unit":"g","cat":"skafferi"},{"name":"purjolök","amount":150,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"gul paprika","amount":150,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"champinjoner","amount":100,"unit":"g","cat":"grönt"},{"name":"smör (att steka i)","toTaste":true,"cat":"mejeri"},{"name":"crème fraiche","amount":200,"unit":"ml","cat":"mejeri"},{"name":"fiskfond","amount":15,"unit":"ml","cat":"skafferi"},{"name":"chilisås","amount":15,"unit":"ml","cat":"skafferi"},{"name":"kräftstjärtar (konserv, inkl. rom)","amount":175,"unit":"g","count":1,"countUnit":"burk","cat":"kött"},{"name":"dill","amount":15,"unit":"g","cat":"grönt"}],"steps":["Koka pastan enligt anvisningen på förpackningen, så att den blir klar samtidigt som såsen.","Finhacka purjolök och paprika. Skiva svampen om den används.","Smält smör i en stekpanna. Fräs purjolök, paprika och ev. svamp i 5-10 minuter tills svampens vätska kokat in.","Tillsätt crème fraiche, fiskfond, chilisås och kräftrom (avskilj från kräftstjärtarna). Rör om och låt sjuda några minuter, smaka av.","Tillsätt kräftstjärtarna och dillen sist. Rör försiktigt och värm 1-2 minuter, såsen ska inte koka. Servera genast med pastan."]},{"id":"flaskfile","title":"Absolut bästa fläskfilén","portions":4,"course":"huvudratt","source":"https://matklubben.se/recept/absolut-baesta-flaeskfilen/","ingredients":[{"name":"fläskfilé","amount":1200,"unit":"g","count":2,"countUnit":"st","cat":"kött"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"mascarpone","amount":250,"unit":"g","count":1,"countUnit":"burk","cat":"mejeri"},{"name":"grönsaksbuljongtärning","amount":22,"unit":"g","count":2,"countUnit":"st","cat":"skafferi"},{"name":"crème fraiche","amount":200,"unit":"ml","cat":"mejeri"},{"name":"vispgrädde","amount":300,"unit":"ml","cat":"mejeri"},{"name":"sambal oelek","amount":5,"unit":"ml","cat":"skafferi"},{"name":"mango chutney","amount":100,"unit":"ml","cat":"skafferi"},{"name":"röd paprika","amount":180,"unit":"g","count":1,"countUnit":"st","cat":"grönt"}],"steps":["Dela varje filé på längden, dela sedan längderna i 3-4 bitar. Salta och peppra, bryn i en stekpanna tills de fått fin färg. Lägg över i en ugnsform.","Vispa ihop mascarpone, grädde, crème fraiche, sambal oelek, mango chutney och buljongtärningar, värm blandningen. Skär paprikan i mindre bitar och blanda ner i såsen. Låt sjuda kort, häll sedan över köttet.","Grädda mitt i ugnen på 200 grader i ca 45 minuter. Klart att servera!"]},{"id":"chilirakor","title":"Chiliräkor med avocadosalsa","portions":4,"course":"forratt","source":"","ingredients":[{"name":"räkor (avrunna)","amount":500,"unit":"g","group":"Räkor","cat":"kött"},{"name":"chilisås (heinz)","amount":50,"unit":"ml","group":"Räkor","cat":"skafferi"},{"name":"olivolja","amount":50,"unit":"ml","group":"Räkor","cat":"skafferi"},{"name":"vitvinsvinäger","amount":30,"unit":"ml","group":"Räkor","cat":"skafferi"},{"name":"vitlök","amount":15,"unit":"g","count":3,"countUnit":"klyftor","group":"Räkor","cat":"grönt"},{"name":"salt","amount":2,"unit":"g","group":"Räkor","cat":"skafferi"},{"name":"cayennepeppar","amount":2,"unit":"g","group":"Räkor","cat":"skafferi"},{"name":"avokado","amount":540,"unit":"g","count":3,"countUnit":"st","group":"Avocadosalsa","cat":"grönt"},{"name":"mango (gärna fryst, tärnad)","amount":350,"unit":"g","count":1,"countUnit":"st","group":"Avocadosalsa","cat":"fryst"},{"name":"olivolja (salsa)","amount":30,"unit":"ml","group":"Avocadosalsa","cat":"skafferi"},{"name":"grön chilifrukt","amount":15,"unit":"g","count":1,"countUnit":"st","group":"Avocadosalsa","cat":"grönt"},{"name":"persilja","amount":4,"unit":"g","count":2,"countUnit":"kvistar","group":"Avocadosalsa","cat":"grönt"},{"name":"limejuice","amount":30,"unit":"ml","group":"Avocadosalsa","cat":"skafferi"},{"name":"salt","toTaste":true,"group":"Avocadosalsa","cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"group":"Avocadosalsa","cat":"skafferi"}],"steps":["Blanda chilisås, olivolja, vitvinsvinäger, vitlök, salt och cayennepeppar till en marinad. Vänd ner räkorna och låt dra en stund i kylen.","Till avocadosalsan: tärna avokado och mango grovt. Finhacka chilifrukten (undvik hudkontakt, den svider) och strimla persiljan.","Blanda avokado, mango, chili och persilja med olivolja och limejuice. Smaka av med salt och peppar.","Servera räkorna tillsammans med avocadosalsan."]},{"id":"arengs-bloody-mary","title":"Årengs Bloody Mary","portions":2,"course":"dryck","source":"https://emil.cafe.se/dags-att-borja-tanka-pa-brunch/","ingredients":[{"name":"vodka","amount":120,"unit":"ml","cat":"övrigt"},{"name":"citronjuice","amount":30,"unit":"ml","cat":"skafferi"},{"name":"worcestersås","amount":10,"unit":"ml","cat":"skafferi"},{"name":"tabasco","amount":0.4,"unit":"ml","count":8,"countUnit":"droppar","cat":"skafferi"},{"name":"japansk soja","amount":30,"unit":"ml","cat":"skafferi"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"sellerisalt","toTaste":true,"cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"tomatjuice","amount":300,"unit":"ml","cat":"skafferi"},{"name":"flingsalt (till glaskanten)","toTaste":true,"cat":"skafferi"},{"name":"selleristjälkar (garnering)","toTaste":true,"cat":"grönt"}],"steps":["Rör alla ingredienser (utom flingsalt och selleristjälkar) på is i ungefär 15 sekunder, tills drinken är lagom utspädd men inte blaskig.","Dra en citronskiva runt glaskanten och doppa i en blandning av 1/3 sellerisalt och 2/3 flingsalt.","Häll upp drinken i glasen och garnera med selleristjälkar eller picklat."]},{"id":"strawberry-daiquiri","title":"Strawberry Daiquiri","portions":1,"course":"dryck","source":"https://www.tasteline.com/recept/strawberry-daiquiri/","ingredients":[{"name":"ljus rom","amount":40,"unit":"ml","cat":"övrigt"},{"name":"jordgubbar","amount":60,"unit":"g","count":5,"countUnit":"st","cat":"grönt"},{"name":"limejuice","amount":20,"unit":"ml","cat":"skafferi"},{"name":"sockerlag","amount":10,"unit":"ml","cat":"skafferi"},{"name":"is, krossad","toTaste":true,"skipList":true,"cat":"övrigt"}],"steps":["Mixa alla ingredienser i en blender tills konsistensen påminner om sorbet.","Häll upp i ett margaritaglas. Garnera med en jordgubbe."]},{"id":"nubbesallad","title":"Nubbesallad","portions":6,"course":"sas","source":"","ingredients":[{"name":"gräddfil","amount":75,"unit":"ml","cat":"mejeri"},{"name":"majonnäs","amount":150,"unit":"ml","cat":"skafferi"},{"name":"rökt kaviar (eller vanlig)","amount":60,"unit":"ml","cat":"skafferi"},{"name":"rödlök","amount":60,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"purjolök, finhackad","amount":50,"unit":"ml","cat":"grönt"},{"name":"dill, finhackad","amount":50,"unit":"ml","cat":"grönt"},{"name":"matjesfiléer","amount":220,"unit":"g","count":1,"countUnit":"burk","cat":"kött"},{"name":"potatis (kokt, kall)","amount":500,"unit":"g","count":5,"countUnit":"st","cat":"grönt"},{"name":"ägg, hårdkokta","amount":360,"unit":"g","count":6,"countUnit":"st","cat":"mejeri"},{"name":"persilja","amount":40,"unit":"g","count":1,"countUnit":"bunt","cat":"grönt"}],"steps":["Hacka rödlöken. Skär potatisen i små tärningar.","Skär matjesfiléerna i små bitar.","Hacka 4 av äggen (spara 2 hela till garnering).","Blanda gräddfil, majonnäs och kaviar.","Rör ner rödlök, purjolök och dill.","Blanda till sist i potatis och matjes.","Garnera med de 2 sparade äggen, klyftade, samt persilja. Salladen kan med fördel stå i kylen ett par timmar före servering."]},{"id":"morots-och-ingefarssoppa","title":"Morots- och ingefärssoppa med jordnötshack","portions":4,"course":"huvudratt","source":"https://www.ica.se/recept/morots-och-ingefarssoppa-med-jordnotshack-715749/","ingredients":[{"name":"minibaguetter","amount":200,"unit":"g","count":4,"countUnit":"st","group":"Soppa","cat":"skafferi"},{"name":"gul lök","amount":110,"unit":"g","count":1,"countUnit":"st","group":"Soppa","cat":"grönt"},{"name":"vitlök","amount":5,"unit":"g","count":1,"countUnit":"klyftor","group":"Soppa","cat":"grönt"},{"name":"morot","amount":500,"unit":"g","group":"Soppa","cat":"grönt"},{"name":"ingefära, riven","amount":6,"unit":"g","group":"Soppa","cat":"grönt"},{"name":"olja","amount":5,"unit":"ml","group":"Soppa","cat":"skafferi"},{"name":"hönsbuljong","amount":500,"unit":"ml","group":"Soppa","cat":"skafferi"},{"name":"lime","amount":65,"unit":"g","count":1,"countUnit":"st","group":"Soppa","cat":"grönt"},{"name":"kokosmjölk","amount":400,"unit":"ml","group":"Soppa","cat":"skafferi"},{"name":"sambal oelek","amount":5,"unit":"ml","group":"Soppa","cat":"skafferi"},{"name":"salt","toTaste":true,"group":"Soppa","cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"group":"Soppa","cat":"skafferi"},{"name":"salta jordnötter","amount":55,"unit":"g","group":"Jordnötshack","cat":"skafferi"},{"name":"koriander","amount":12,"unit":"g","count":0.5,"countUnit":"kruka","group":"Jordnötshack","cat":"grönt"}],"steps":["Grädda brödet enligt anvisningen på förpackningen.","Skala och finhacka lök och vitlök. Skala och skär morötterna i mindre bitar. Skala och riv ingefäran.","Fräs lök, vitlök och morötter i oljan i en stor kastrull ca 5 minuter. Tillsätt buljongen, ingefäran och pressad limesaft. Koka upp och låt småkoka under lock ca 15 minuter tills morötterna är mjuka.","Jordnötshack: hacka och blanda jordnötter och koriander grovt.","Ta soppan från värmen. Mixa den slät med stavmixer eller matberedare. Tillsätt kokosmjölken och värm upp soppan. Smaka av med sambal oelek, salt och peppar.","Servera soppan med jordnötshack och bröd."]}],"selections":[],"extras":[],"checked":[],"struck":{}}')
  ON CONFLICT(name) DO UPDATE SET state = excluded.state;
DELETE FROM recipes_index WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'kottfarssas', 'Köttfärssås', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'kottfarssas'), '{"id":"kottfarssas","title":"Köttfärssås","portions":6,"course":"huvudratt","source":"","ingredients":[{"name":"nötfärs","amount":800,"unit":"g","cat":"kött"},{"name":"gul lök","amount":220,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"morot","amount":240,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"stjälkselleri","amount":80,"unit":"g","count":2,"countUnit":"stjälkar","cat":"grönt"},{"name":"vitlök","amount":20,"unit":"g","count":4,"countUnit":"klyftor","cat":"grönt"},{"name":"olivolja","amount":100,"unit":"ml","cat":"skafferi"},{"name":"tomatpuré","amount":90,"unit":"ml","cat":"skafferi"},{"name":"rött vin (eller vatten)","amount":200,"unit":"ml","cat":"övrigt"},{"name":"krossade tomater","amount":800,"unit":"g","cat":"skafferi"},{"name":"torkad oregano","amount":3,"unit":"g","cat":"skafferi"},{"name":"torkad timjan","amount":2,"unit":"g","cat":"skafferi"},{"name":"lagerblad","amount":1,"unit":"g","count":2,"countUnit":"st","cat":"skafferi"},{"name":"salt","amount":12,"unit":"g","cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"pasta (till servering)","amount":480,"unit":"g","cat":"skafferi"}],"steps":["Finhacka lök, morot och selleri så fint du kan. Fräs mjukt i olivoljan utan att det tar färg.","Tryck till vitlöksklyftorna med knivbladet, finhacka och låt fräsa med i någon minut.","Tillsätt köttfärsen lite i taget så att den bryns och inte kokar. Tillsätt tomatpurén och fräs någon minut till.","Häll i vinet (eller vattnet) och låt koka upp snabbt.","Tillsätt krossade tomater, oregano, timjan och lagerblad. Salta och peppra. Låt puttra under lock i minst 20 minuter, gärna längre.","Servera med nykokt pasta."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'kebab', 'Kebab i långpanna', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'kebab'), '{"id":"kebab","title":"Kebab i långpanna","portions":6,"course":"huvudratt","source":"https://zeinaskitchen.se/kafta-kottfarskebab-i-langpanna/","ingredients":[{"name":"köttfärs","amount":1000,"unit":"g","group":"Kebaben","cat":"kött"},{"name":"rödlök","amount":80,"unit":"g","count":1,"countUnit":"st","group":"Kebaben","cat":"grönt"},{"name":"persilja","amount":40,"unit":"g","count":1,"countUnit":"bunt","group":"Kebaben","cat":"grönt"},{"name":"vitlök","amount":5,"unit":"g","count":1,"countUnit":"klyftor","group":"Kebaben","cat":"grönt"},{"name":"gurkmeja","amount":3,"unit":"g","group":"Kebaben","cat":"skafferi"},{"name":"kaftakrydda (eller 7 kryddor)","amount":4,"unit":"g","group":"Kebaben","cat":"skafferi"},{"name":"salt","amount":6,"unit":"g","group":"Kebaben","cat":"skafferi"},{"name":"svartpeppar","amount":3,"unit":"g","group":"Kebaben","cat":"skafferi"},{"name":"rödlök","amount":200,"unit":"g","count":2,"countUnit":"st","group":"Garnering","cat":"grönt"},{"name":"sivri (turkisk paprika) eller grön paprika","amount":150,"unit":"g","group":"Garnering","cat":"grönt"},{"name":"tomat","amount":360,"unit":"g","count":3,"countUnit":"st","group":"Garnering","cat":"grönt"},{"name":"olivolja","amount":70,"unit":"ml","group":"Garnering","cat":"skafferi"},{"name":"sumak (eller citron)","amount":10,"unit":"g","group":"Garnering","cat":"skafferi"}],"steps":["Blanda alla ingredienser till kebaben. Blanda inte färsen mer än nödvändigt, då trådar den sig och blir seg.","Platta ut köttet jämnt i en långpanna, ca 30×40 cm. Skär ut jämnstora kebabbitar.","Skär rödlöken i klyftor, gör ett kryss på tomaterna och lägg dem över färsen tillsammans med sivri eller paprikaklyftor.","Värm ugnen till 275 grader, gärna med grillfunktion. Ringla olivolja över allt på plåten och strö på sumak.","Grilla mitt i ugnen ca 15 minuter. Servera genast med sallad, pommes, ris eller bulgur."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'lovbiff-teriyaki', 'Lövbiff teriyaki med pak choi', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'lovbiff-teriyaki'), '{"id":"lovbiff-teriyaki","title":"Lövbiff teriyaki med pak choi","portions":8,"course":"huvudratt","source":"https://www.ica.se/recept/lovbiff-teriyaki-med-pak-choi-och-lime-719793/","ingredients":[{"name":"ris (gärna jasmin)","amount":500,"unit":"g","cat":"skafferi"},{"name":"japansk soja","amount":200,"unit":"ml","group":"Sås","cat":"skafferi"},{"name":"vatten","amount":100,"unit":"ml","group":"Sås","skipList":true,"cat":"övrigt"},{"name":"honung (eller strösocker)","amount":100,"unit":"ml","group":"Sås","cat":"skafferi"},{"name":"färsk ingefära","amount":30,"unit":"g","group":"Sås","cat":"grönt"},{"name":"vitlök","amount":10,"unit":"g","count":2,"countUnit":"klyftor","group":"Sås","cat":"grönt"},{"name":"majsstärkelse","amount":6,"unit":"g","group":"Sås","cat":"skafferi"},{"name":"sambal oelek","amount":20,"unit":"ml","group":"Grönsaker","cat":"skafferi"},{"name":"lime","amount":130,"unit":"g","count":2,"countUnit":"st","group":"Grönsaker","cat":"grönt"},{"name":"olja","amount":30,"unit":"ml","group":"Grönsaker","cat":"skafferi"},{"name":"salt","toTaste":true,"group":"Grönsaker","cat":"skafferi"},{"name":"stjälkselleri","amount":450,"unit":"g","count":1,"countUnit":"förp","group":"Grönsaker","cat":"grönt"},{"name":"pak choi","amount":500,"unit":"g","group":"Grönsaker","cat":"grönt"},{"name":"lövbiff","amount":1000,"unit":"g","group":"Kött","cat":"kött"},{"name":"olja","amount":30,"unit":"ml","group":"Kött","cat":"skafferi"},{"name":"sesamfrön","amount":20,"unit":"g","group":"Kött","cat":"skafferi"}],"steps":["Koka riset enligt anvisningen på förpackningen.","Sås: blanda alla ingredienser i en kastrull. Koka såsen 3–5 minuter under omrörning.","Grönsaker: blanda sambal oelek, pressad limesaft och olja i en skål. Smaka av med salt. Ansa och strimla selleri och pak choi, vänd ner grönsakerna.","Strimla köttet. Stek det i oljan i omgångar i en het stekpanna tills det fått fin färg.","Häll på såsen och koka några minuter. Strö sesamfrön över köttet.","Servera köttet med ris och grönsaker."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'veg-lasagne', 'Vegetarisk lasagne', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'veg-lasagne'), '{"id":"veg-lasagne","title":"Vegetarisk lasagne","portions":8,"course":"huvudratt","source":"https://undertian.com/recept/billig-vegetarisk-lasagne/","ingredients":[{"name":"gul lök","amount":220,"unit":"g","count":2,"countUnit":"st","group":"Lins- och tomatsås","cat":"grönt"},{"name":"röda linser (torkade)","amount":340,"unit":"g","group":"Lins- och tomatsås","cat":"skafferi"},{"name":"krossade tomater","amount":800,"unit":"g","group":"Lins- och tomatsås","cat":"skafferi"},{"name":"vatten","amount":600,"unit":"ml","group":"Lins- och tomatsås","skipList":true,"cat":"övrigt"},{"name":"morot","amount":480,"unit":"g","count":4,"countUnit":"st","group":"Lins- och tomatsås","cat":"grönt"},{"name":"grönsaksbuljongtärning","amount":22,"unit":"g","count":2,"countUnit":"st","group":"Lins- och tomatsås","cat":"skafferi"},{"name":"tomatpuré","amount":30,"unit":"ml","group":"Lins- och tomatsås","cat":"skafferi"},{"name":"vitlök","amount":10,"unit":"g","count":2,"countUnit":"klyftor","group":"Lins- och tomatsås","cat":"grönt"},{"name":"torkade örter (basilika/oregano/timjan)","amount":6,"unit":"g","group":"Lins- och tomatsås","cat":"skafferi"},{"name":"salt","toTaste":true,"group":"Lins- och tomatsås","cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"group":"Lins- och tomatsås","cat":"skafferi"},{"name":"olja att steka i","toTaste":true,"group":"Lins- och tomatsås","cat":"skafferi"},{"name":"crème fraiche","amount":500,"unit":"ml","group":"Ostsås","cat":"mejeri"},{"name":"riven ost","amount":80,"unit":"g","group":"Ostsås","cat":"mejeri"},{"name":"lasagneplattor","amount":500,"unit":"g","group":"Montering","cat":"skafferi"},{"name":"riven ost","amount":50,"unit":"g","group":"Montering","cat":"mejeri"}],"steps":["Hacka löken fint. Värm olja i en stor kastrull och stek löken tills den är blank.","Skölj linserna i kallt vatten. Lägg dem i kastrullen och slå på krossade tomater och vatten. Riv morötterna och lägg i. Tillsätt buljongtärning och tomatpuré. Koka under lock ca 10 minuter på medelsvag värme, rör om då och då.","Sätt ugnen på 225 grader.","Späd såsen med mer vatten om det behövs, den ska vara tjock men inte rinnig. Pressa i vitlöken och smaka av med salt, peppar och örterna.","Ostsås: värm crème fraiche i en kastrull och blanda i den rivna osten. Låt osten smälta, såsen ska inte koka. Salta och peppra.","Smörj en ugnsform. Lägg tomatsås i botten och varva med lasagneplattor, tomatsås och ostsås tills plattorna är slut. Avsluta med ostsås och strö ost överst.","Grädda mitt i ugnen ca 20 minuter, håll koll så lasagnen inte bränns.","Servera med en sallad."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'broccolisoppa', 'Broccolisoppa', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'broccolisoppa'), '{"id":"broccolisoppa","title":"Broccolisoppa","portions":6,"course":"huvudratt","source":"https://www.allrecipes.com/recipe/13313/best-cream-of-broccoli-soup/","ingredients":[{"name":"smör","amount":55,"unit":"g","cat":"mejeri"},{"name":"gul lök","amount":110,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"stjälkselleri","amount":40,"unit":"g","count":1,"countUnit":"stjälkar","cat":"grönt"},{"name":"kycklingbuljong","amount":720,"unit":"ml","cat":"skafferi"},{"name":"broccoli","amount":700,"unit":"g","cat":"grönt"},{"name":"vetemjöl","amount":25,"unit":"g","cat":"skafferi"},{"name":"mjölk","amount":480,"unit":"ml","cat":"mejeri"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"}],"steps":["Smält ungefär en tredjedel av smöret i en kastrull. Fräs lök och selleri tills de mjuknat.","Tillsätt broccoli och buljong. Låt sjuda under lock i 10 minuter.","Mixa soppan slät med stavmixer, eller i mixer i omgångar.","Smält resten av smöret i en liten kastrull. Rör i mjölet och späd med mjölken. Rör tills det tjocknar och bubblar, blanda sedan ner i soppan.","Smaka av med svartpeppar."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'loomisar', 'Haloumipasta', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'loomisar'), '{"id":"loomisar","title":"Haloumipasta","portions":6,"course":"huvudratt","source":"","ingredients":[{"name":"halloumi","amount":200,"unit":"g","count":1,"countUnit":"pkt","cat":"mejeri"},{"name":"rödpesto","amount":95,"unit":"g","count":0.5,"countUnit":"burk","cat":"skafferi"},{"name":"svarta oliver (urkärnade)","amount":150,"unit":"g","count":1,"countUnit":"burk","cat":"skafferi"},{"name":"tomat","amount":720,"unit":"g","count":6,"countUnit":"st","cat":"grönt"},{"name":"rödlök","amount":100,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"vitlök","toTaste":true,"cat":"grönt"},{"name":"pasta (till servering)","amount":480,"unit":"g","cat":"skafferi"}],"steps":["Hacka lök, vitlök och tomater.","Skär halloumi i kuber, halvera oliver och stek tillsammans.","Stek lök, vitlök och sedan tomater.","Blanda ihop med rödpesto och låt puttra ett tag.","Rör ihop med pasta och servera."]}');
