INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'marockansk-kyckling', 'Marockansk kyckling med sötpotatismos', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'marockansk-kyckling'), '{"id":"marockansk-kyckling","title":"Marockansk kyckling med sötpotatismos","portions":4,"course":"huvudratt","source":"https://www.bbcgoodfood.com/recipes/moroccan-chicken-sweet-potato-mash","ingredients":[{"name":"sötpotatis","amount":1000,"unit":"g","cat":"grönt"},{"name":"ras el hanout (eller kanel och spiskummin)","amount":10,"unit":"g","cat":"skafferi"},{"name":"kycklingfilé","amount":600,"unit":"g","count":4,"countUnit":"st","cat":"kött"},{"name":"olivolja","amount":30,"unit":"ml","cat":"skafferi"},{"name":"gul lök","amount":110,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"vitlök","amount":5,"unit":"g","count":1,"countUnit":"klyfta","cat":"grönt"},{"name":"kycklingbuljong","amount":200,"unit":"ml","cat":"skafferi"},{"name":"honung","amount":10,"unit":"ml","cat":"skafferi"},{"name":"citron","amount":50,"unit":"g","count":0.5,"countUnit":"st","cat":"grönt"},{"name":"gröna oliver","amount":50,"unit":"g","cat":"skafferi"},{"name":"koriander","amount":20,"unit":"g","cat":"grönt"}],"steps":["Koka sötpotatisen i saltat vatten i 15 minuter eller tills mör. Blanda ras el hanout med salt och peppar och gnid in på kycklingen. Bryn kycklingen i olja i en stekpanna, ca 3 minuter per sida, tills gyllene.","Lyft ur kycklingen. Fräs lök och vitlök i 5 minuter tills mjuka. Tillsätt buljong, honung, citronjuice och oliver, lägg tillbaka kycklingen och låt sjuda 10 minuter tills såsen tjocknat och kycklingen är genomstekt.","Mosa sötpotatisen med lite olja, salta och peppra. Skiva kycklingen och rör ner koriandern i såsen. Servera kycklingen och såsen på moset."]}');
