    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'rakpasta'), '{"id":"rakpasta","title":"Räkpasta med chili och vitlök","portions":4,"course":"huvudratt","source":"https://mittkok.expressen.se/recept/spaghetti-med-rakor-chili-och-vitlok/","ingredients":[{"name":"spagetti","amount":400,"unit":"g","cat":"skafferi"},{"name":"räkor (skalade)","amount":300,"unit":"g","cat":"kött"},{"name":"olivolja","amount":100,"unit":"ml","cat":"skafferi"},{"name":"vitlök","amount":15,"unit":"g","count":3,"countUnit":"klyftor","cat":"grönt"},{"name":"röd chili","amount":15,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"miniplommontomater","amount":200,"unit":"g","cat":"grönt"},{"name":"salt","amount":3,"unit":"g","cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"citron","amount":33,"unit":"g","count":0.5,"countUnit":"st","cat":"grönt"},{"name":"rucolasallad","amount":70,"unit":"g","cat":"grönt"},{"name":"parmesanost","amount":100,"unit":"g","cat":"mejeri"}],"steps":[]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'chili-con-carne', 'Chili con carne', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'chili-con-carne'), '{"id":"chili-con-carne","title":"Chili con carne","portions":4,"course":"huvudratt","source":"","ingredients":[{"name":"nötfärs","amount":500,"unit":"g","cat":"kött"},{"name":"gul lök","amount":220,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"vitlök","amount":10,"unit":"g","count":2,"countUnit":"klyftor","cat":"grönt"},{"name":"röd chili","amount":15,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"grön paprika","amount":150,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"tomatpuré","amount":30,"unit":"ml","cat":"skafferi"},{"name":"hela tomater (burk)","amount":400,"unit":"g","count":1,"countUnit":"burk","cat":"skafferi"},{"name":"vatten","amount":400,"unit":"ml","skipList":true,"cat":"övrigt"},{"name":"kidneybönor (avrunna)","amount":480,"unit":"g","count":1,"countUnit":"pkt","cat":"skafferi"},{"name":"torkad timjan","amount":2,"unit":"g","cat":"skafferi"},{"name":"torkad oregano","amount":3,"unit":"g","cat":"skafferi"},{"name":"malen spiskummin","amount":4,"unit":"g","cat":"skafferi"},{"name":"rökt paprikapulver","amount":2,"unit":"g","cat":"skafferi"},{"name":"kakao","amount":5,"unit":"g","cat":"skafferi"},{"name":"bbq-sås","amount":30,"unit":"ml","cat":"skafferi"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"koriander","amount":20,"unit":"g","count":1,"countUnit":"kruka","cat":"grönt"},{"name":"olivolja","toTaste":true,"cat":"skafferi"},{"name":"ris (till servering)","toTaste":true,"cat":"skafferi"}],"steps":[]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'kycklingsallad-tex-mex', 'Kycklingsallad tex mex', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'kycklingsallad-tex-mex'), '{"id":"kycklingsallad-tex-mex","title":"Kycklingsallad tex mex","portions":4,"course":"huvudratt","source":"https://www.tasteline.com/recept/texmexsallad-med-kyckling/","ingredients":[{"name":"kyckling","amount":800,"unit":"g","cat":"kött"},{"name":"smör","amount":30,"unit":"g","cat":"mejeri"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"texmexkrydda","amount":12,"unit":"g","cat":"skafferi"},{"name":"röd paprika","amount":300,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"avokado","amount":600,"unit":"g","count":4,"countUnit":"st","cat":"grönt"},{"name":"tomat","amount":480,"unit":"g","count":4,"countUnit":"st","cat":"grönt"},{"name":"rödlök","amount":160,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"majs (fryst, tinad)","amount":170,"unit":"g","cat":"fryst"},{"name":"svarta bönor (kokta)","amount":340,"unit":"g","cat":"skafferi"},{"name":"blandad sallad","amount":200,"unit":"g","count":2,"countUnit":"påse","cat":"grönt"},{"name":"salsa (texmex)","amount":300,"unit":"ml","cat":"skafferi"},{"name":"gräddfil","amount":200,"unit":"ml","cat":"mejeri"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"}],"steps":["Skär kycklingen i små bitar, stek i smör. Salta och peppra och krydda med texmexblandning, rör runt och lägg sedan i en skål. Låt svalna lite.","Skär paprika, avokado och tomat i bitar.","Finhacka löken. Lägg allt i skålen med kyckling. Skölj bönorna och tillsätt dessa. Tillsätt sallad och majs. Blanda runt och servera med salsa och gräddfil."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'teriyaki-biff', 'Teriyaki biff', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'teriyaki-biff'), '{"id":"teriyaki-biff","title":"Teriyaki biff","portions":8,"course":"huvudratt","source":"https://www.kokaihop.se/recept/biff-teriyaki","ingredients":[{"name":"lövbiff","amount":800,"unit":"g","cat":"kött"},{"name":"morot","amount":480,"unit":"g","count":4,"countUnit":"st","cat":"grönt"},{"name":"gul lök","amount":220,"unit":"g","count":2,"countUnit":"st","cat":"grönt"},{"name":"broccoli","amount":800,"unit":"g","count":2,"countUnit":"huvuden","cat":"grönt"},{"name":"olja","amount":30,"unit":"ml","cat":"skafferi"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"teriyakisås","amount":200,"unit":"ml","cat":"skafferi"},{"name":"kinesisk soja","amount":60,"unit":"ml","cat":"skafferi"},{"name":"sambal oelek","amount":10,"unit":"ml","cat":"skafferi"},{"name":"grädde (kokbar)","amount":500,"unit":"ml","cat":"mejeri"}],"steps":["Skala och skiva löken.","Skala morötterna och skär tunna skivor på snedden.","Dela broccolin i små bitar.","Fräs köttet lite i taget i stor stekpanna eller wokpanna.","Ta upp allt köttet och fräs grönsakerna under omrörning tills de börjar mjukna.","Lägg tillbaka köttet och salta, men inte för mycket.","Tillsätt teriyakisåsen, sojan, sambal oelek och grädden och låt småkoka några minuter."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'gazpacho', 'Gazpacho', 'forratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'gazpacho'), '{"id":"gazpacho","title":"Gazpacho","portions":4,"course":"forratt","source":"https://youtu.be/OZkE_d2CwBw","ingredients":[{"name":"gurka","amount":400,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"plommontomater","amount":490,"unit":"g","count":7,"countUnit":"st","cat":"grönt"},{"name":"röd paprika","amount":150,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"grön paprika","amount":150,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"silverlök","amount":20,"unit":"g","cat":"grönt"},{"name":"vitlök","amount":2.5,"unit":"g","count":0.5,"countUnit":"klyfta","cat":"grönt"},{"name":"olivolja","amount":60,"unit":"ml","cat":"skafferi"},{"name":"sherryvinäger","amount":20,"unit":"ml","cat":"skafferi"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"strösocker","toTaste":true,"cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"vitt bröd (till krutonger)","toTaste":true,"cat":"skafferi"}],"steps":[]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'sommarsmorgastarta', 'Sommarsmörgåstårta', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'sommarsmorgastarta'), '{"id":"sommarsmorgastarta","title":"Sommarsmörgåstårta","portions":8,"course":"huvudratt","source":"https://www.niiinis.se/2020/06/19/sommarsmorgastarta-med-farskpotatis/","ingredients":[{"name":"jubileumskaka (runt rågbröd)","amount":1200,"unit":"g","count":2,"countUnit":"st","cat":"skafferi"},{"name":"crème fraiche","amount":500,"unit":"ml","cat":"mejeri"},{"name":"färskost","amount":300,"unit":"g","cat":"mejeri"},{"name":"rödlök","amount":110,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"dill","amount":25,"unit":"g","count":1,"countUnit":"bunt","cat":"grönt"},{"name":"cayennepeppar","amount":2,"unit":"g","cat":"skafferi"},{"name":"honung","amount":30,"unit":"ml","cat":"skafferi"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"ägg","amount":180,"unit":"g","count":3,"countUnit":"st","cat":"mejeri"},{"name":"handskalade räkor","amount":200,"unit":"g","cat":"kött"},{"name":"färskpotatis","amount":400,"unit":"g","count":4,"countUnit":"st","cat":"grönt"},{"name":"handskalade räkor","amount":300,"unit":"g","group":"Garnering","cat":"kött"},{"name":"ägg","amount":180,"unit":"g","count":3,"countUnit":"st","group":"Garnering","cat":"mejeri"},{"name":"färskpotatis","amount":400,"unit":"g","count":4,"countUnit":"st","group":"Garnering","cat":"grönt"},{"name":"salladslök","amount":15,"unit":"g","count":0.5,"countUnit":"st","group":"Garnering","cat":"grönt"}],"steps":["Koka potatisen (till både fyllning och garnering), låt sedan svalna.","Vispa crème fraiche fluffig och blanda med färskost, hackad rödlök, hackad dill, cayennepeppar och honung. Salta och peppra.","Lägg ut ett bröd på ett stort fat. Bred ut hälften av fyllningen. Skiva färskpotatis och lägg på, dela äggen i klyftor och lägg på dem också. Toppa med lite räkor.","Lägg på det andra brödet. Bred ut resten av fyllningen och toppa snyggt med garneringens räkor, ägg, potatis och salladslök. Låt stå kallt någon timme innan servering."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'grillsasen', 'Grillsåsen', 'sas', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'grillsasen'), '{"id":"grillsasen","title":"Grillsåsen","portions":6,"course":"sas","source":"","ingredients":[{"name":"crème fraiche","amount":300,"unit":"g","count":1,"countUnit":"burk","cat":"mejeri"},{"name":"mango chutney","amount":38,"unit":"ml","cat":"skafferi"},{"name":"vitlök","amount":5,"unit":"g","count":1,"countUnit":"klyfta","cat":"grönt"},{"name":"ingefära (malen)","amount":1,"unit":"g","cat":"skafferi"},{"name":"curry","amount":1,"unit":"g","cat":"skafferi"},{"name":"cayennepeppar","toTaste":true,"cat":"skafferi"},{"name":"rödlök","amount":40,"unit":"g","count":1,"countUnit":"st","cat":"grönt"}],"steps":["Blanda crème fraiche, mango chutney, pressad vitlök, ingefära, curry, cayennepeppar och finhackad rödlök.","Smaka av och låt gärna stå kallt en stund innan servering."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'pasta-kraftstjartar', 'Pastasås med kräftstjärtar', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'pasta-kraftstjartar'), '{"id":"pasta-kraftstjartar","title":"Pastasås med kräftstjärtar","portions":3,"course":"huvudratt","source":"https://www.recepten.se/recept/pasta_kraeftstjaertar.html","ingredients":[{"name":"bandspagetti","amount":300,"unit":"g","cat":"skafferi"},{"name":"purjolök","amount":150,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"gul paprika","amount":150,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"champinjoner","amount":100,"unit":"g","cat":"grönt"},{"name":"smör (att steka i)","toTaste":true,"cat":"mejeri"},{"name":"crème fraiche","amount":200,"unit":"ml","cat":"mejeri"},{"name":"fiskfond","amount":15,"unit":"ml","cat":"skafferi"},{"name":"chilisås","amount":15,"unit":"ml","cat":"skafferi"},{"name":"kräftstjärtar (konserv, inkl. rom)","amount":175,"unit":"g","count":1,"countUnit":"burk","cat":"kött"},{"name":"dill","amount":15,"unit":"g","cat":"grönt"}],"steps":["Koka pastan enligt anvisningen på förpackningen, så att den blir klar samtidigt som såsen.","Finhacka purjolök och paprika. Skiva svampen om den används.","Smält smör i en stekpanna. Fräs purjolök, paprika och ev. svamp i 5-10 minuter tills svampens vätska kokat in.","Tillsätt crème fraiche, fiskfond, chilisås och kräftrom (avskilj från kräftstjärtarna). Rör om och låt sjuda några minuter, smaka av.","Tillsätt kräftstjärtarna och dillen sist. Rör försiktigt och värm 1-2 minuter, såsen ska inte koka. Servera genast med pastan."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'flaskfile', 'Absolut bästa fläskfilén', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'flaskfile'), '{"id":"flaskfile","title":"Absolut bästa fläskfilén","portions":4,"course":"huvudratt","source":"https://matklubben.se/recept/absolut-baesta-flaeskfilen/","ingredients":[{"name":"fläskfilé","amount":1200,"unit":"g","count":2,"countUnit":"st","cat":"kött"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"mascarpone","amount":250,"unit":"g","count":1,"countUnit":"burk","cat":"mejeri"},{"name":"grönsaksbuljongtärning","amount":22,"unit":"g","count":2,"countUnit":"st","cat":"skafferi"},{"name":"crème fraiche","amount":200,"unit":"ml","cat":"mejeri"},{"name":"vispgrädde","amount":300,"unit":"ml","cat":"mejeri"},{"name":"sambal oelek","amount":5,"unit":"ml","cat":"skafferi"},{"name":"mango chutney","amount":100,"unit":"ml","cat":"skafferi"},{"name":"röd paprika","amount":180,"unit":"g","count":1,"countUnit":"st","cat":"grönt"}],"steps":["Dela varje filé på längden, dela sedan längderna i 3-4 bitar. Salta och peppra, bryn i en stekpanna tills de fått fin färg. Lägg över i en ugnsform.","Vispa ihop mascarpone, grädde, crème fraiche, sambal oelek, mango chutney och buljongtärningar, värm blandningen. Skär paprikan i mindre bitar och blanda ner i såsen. Låt sjuda kort, häll sedan över köttet.","Grädda mitt i ugnen på 200 grader i ca 45 minuter. Klart att servera!"]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'chilirakor', 'Chiliräkor med avocadosalsa', 'forratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'chilirakor'), '{"id":"chilirakor","title":"Chiliräkor med avocadosalsa","portions":4,"course":"forratt","source":"","ingredients":[{"name":"räkor (avrunna)","amount":500,"unit":"g","group":"Räkor","cat":"kött"},{"name":"chilisås (heinz)","amount":50,"unit":"ml","group":"Räkor","cat":"skafferi"},{"name":"olivolja","amount":50,"unit":"ml","group":"Räkor","cat":"skafferi"},{"name":"vitvinsvinäger","amount":30,"unit":"ml","group":"Räkor","cat":"skafferi"},{"name":"vitlök","amount":15,"unit":"g","count":3,"countUnit":"klyftor","group":"Räkor","cat":"grönt"},{"name":"salt","amount":2,"unit":"g","group":"Räkor","cat":"skafferi"},{"name":"cayennepeppar","amount":2,"unit":"g","group":"Räkor","cat":"skafferi"},{"name":"avokado","amount":540,"unit":"g","count":3,"countUnit":"st","group":"Avocadosalsa","cat":"grönt"},{"name":"mango (gärna fryst, tärnad)","amount":350,"unit":"g","count":1,"countUnit":"st","group":"Avocadosalsa","cat":"fryst"},{"name":"olivolja (salsa)","amount":30,"unit":"ml","group":"Avocadosalsa","cat":"skafferi"},{"name":"grön chilifrukt","amount":15,"unit":"g","count":1,"countUnit":"st","group":"Avocadosalsa","cat":"grönt"},{"name":"persilja","amount":4,"unit":"g","count":2,"countUnit":"kvistar","group":"Avocadosalsa","cat":"grönt"},{"name":"limejuice","amount":30,"unit":"ml","group":"Avocadosalsa","cat":"skafferi"},{"name":"salt","toTaste":true,"group":"Avocadosalsa","cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"group":"Avocadosalsa","cat":"skafferi"}],"steps":["Blanda chilisås, olivolja, vitvinsvinäger, vitlök, salt och cayennepeppar till en marinad. Vänd ner räkorna och låt dra en stund i kylen.","Till avocadosalsan: tärna avokado och mango grovt. Finhacka chilifrukten (undvik hudkontakt, den svider) och strimla persiljan.","Blanda avokado, mango, chili och persilja med olivolja och limejuice. Smaka av med salt och peppar.","Servera räkorna tillsammans med avocadosalsan."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'arengs-bloody-mary', 'Årengs Bloody Mary', 'dryck', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'arengs-bloody-mary'), '{"id":"arengs-bloody-mary","title":"Årengs Bloody Mary","portions":2,"course":"dryck","source":"https://emil.cafe.se/dags-att-borja-tanka-pa-brunch/","ingredients":[{"name":"vodka","amount":120,"unit":"ml","cat":"övrigt"},{"name":"citronjuice","amount":30,"unit":"ml","cat":"skafferi"},{"name":"worcestersås","amount":10,"unit":"ml","cat":"skafferi"},{"name":"tabasco","amount":0.4,"unit":"ml","count":8,"countUnit":"droppar","cat":"skafferi"},{"name":"japansk soja","amount":30,"unit":"ml","cat":"skafferi"},{"name":"salt","toTaste":true,"cat":"skafferi"},{"name":"sellerisalt","toTaste":true,"cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"cat":"skafferi"},{"name":"tomatjuice","amount":300,"unit":"ml","cat":"skafferi"},{"name":"flingsalt (till glaskanten)","toTaste":true,"cat":"skafferi"},{"name":"selleristjälkar (garnering)","toTaste":true,"cat":"grönt"}],"steps":["Rör alla ingredienser (utom flingsalt och selleristjälkar) på is i ungefär 15 sekunder, tills drinken är lagom utspädd men inte blaskig.","Dra en citronskiva runt glaskanten och doppa i en blandning av 1/3 sellerisalt och 2/3 flingsalt.","Häll upp drinken i glasen och garnera med selleristjälkar eller picklat."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'strawberry-daiquiri', 'Strawberry Daiquiri', 'dryck', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'strawberry-daiquiri'), '{"id":"strawberry-daiquiri","title":"Strawberry Daiquiri","portions":1,"course":"dryck","source":"https://www.tasteline.com/recept/strawberry-daiquiri/","ingredients":[{"name":"ljus rom","amount":40,"unit":"ml","cat":"övrigt"},{"name":"jordgubbar","amount":60,"unit":"g","count":5,"countUnit":"st","cat":"grönt"},{"name":"limejuice","amount":20,"unit":"ml","cat":"skafferi"},{"name":"sockerlag","amount":10,"unit":"ml","cat":"skafferi"},{"name":"is, krossad","toTaste":true,"skipList":true,"cat":"övrigt"}],"steps":["Mixa alla ingredienser i en blender tills konsistensen påminner om sorbet.","Häll upp i ett margaritaglas. Garnera med en jordgubbe."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'nubbesallad', 'Nubbesallad', 'sas', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'nubbesallad'), '{"id":"nubbesallad","title":"Nubbesallad","portions":6,"course":"sas","source":"","ingredients":[{"name":"gräddfil","amount":75,"unit":"ml","cat":"mejeri"},{"name":"majonnäs","amount":150,"unit":"ml","cat":"skafferi"},{"name":"rökt kaviar (eller vanlig)","amount":60,"unit":"ml","cat":"skafferi"},{"name":"rödlök","amount":60,"unit":"g","count":1,"countUnit":"st","cat":"grönt"},{"name":"purjolök, finhackad","amount":50,"unit":"ml","cat":"grönt"},{"name":"dill, finhackad","amount":50,"unit":"ml","cat":"grönt"},{"name":"matjesfiléer","amount":220,"unit":"g","count":1,"countUnit":"burk","cat":"kött"},{"name":"potatis (kokt, kall)","amount":500,"unit":"g","count":5,"countUnit":"st","cat":"grönt"},{"name":"ägg, hårdkokta","amount":360,"unit":"g","count":6,"countUnit":"st","cat":"mejeri"},{"name":"persilja","amount":40,"unit":"g","count":1,"countUnit":"bunt","cat":"grönt"}],"steps":["Hacka rödlöken. Skär potatisen i små tärningar.","Skär matjesfiléerna i små bitar.","Hacka 4 av äggen (spara 2 hela till garnering).","Blanda gräddfil, majonnäs och kaviar.","Rör ner rödlök, purjolök och dill.","Blanda till sist i potatis och matjes.","Garnera med de 2 sparade äggen, klyftade, samt persilja. Salladen kan med fördel stå i kylen ett par timmar före servering."]}');
INSERT INTO recipes_index (owner_id, id, title, course, visibility, saves_count, data)
  VALUES ((SELECT id FROM users WHERE name = 'grammat'), 'morots-och-ingefarssoppa', 'Morots- och ingefärssoppa med jordnötshack', 'huvudratt', 'public',
    (SELECT COUNT(*) FROM saves WHERE owner_id = (SELECT id FROM users WHERE name = 'grammat') AND recipe_id = 'morots-och-ingefarssoppa'), '{"id":"morots-och-ingefarssoppa","title":"Morots- och ingefärssoppa med jordnötshack","portions":4,"course":"huvudratt","source":"https://www.ica.se/recept/morots-och-ingefarssoppa-med-jordnotshack-715749/","ingredients":[{"name":"minibaguetter","amount":200,"unit":"g","count":4,"countUnit":"st","group":"Soppa","cat":"skafferi"},{"name":"gul lök","amount":110,"unit":"g","count":1,"countUnit":"st","group":"Soppa","cat":"grönt"},{"name":"vitlök","amount":5,"unit":"g","count":1,"countUnit":"klyftor","group":"Soppa","cat":"grönt"},{"name":"morot","amount":500,"unit":"g","group":"Soppa","cat":"grönt"},{"name":"ingefära, riven","amount":6,"unit":"g","group":"Soppa","cat":"grönt"},{"name":"olja","amount":5,"unit":"ml","group":"Soppa","cat":"skafferi"},{"name":"hönsbuljong","amount":500,"unit":"ml","group":"Soppa","cat":"skafferi"},{"name":"lime","amount":65,"unit":"g","count":1,"countUnit":"st","group":"Soppa","cat":"grönt"},{"name":"kokosmjölk","amount":400,"unit":"ml","group":"Soppa","cat":"skafferi"},{"name":"sambal oelek","amount":5,"unit":"ml","group":"Soppa","cat":"skafferi"},{"name":"salt","toTaste":true,"group":"Soppa","cat":"skafferi"},{"name":"svartpeppar","toTaste":true,"group":"Soppa","cat":"skafferi"},{"name":"salta jordnötter","amount":55,"unit":"g","group":"Jordnötshack","cat":"skafferi"},{"name":"koriander","amount":12,"unit":"g","count":0.5,"countUnit":"kruka","group":"Jordnötshack","cat":"grönt"}],"steps":["Grädda brödet enligt anvisningen på förpackningen.","Skala och finhacka lök och vitlök. Skala och skär morötterna i mindre bitar. Skala och riv ingefäran.","Fräs lök, vitlök och morötter i oljan i en stor kastrull ca 5 minuter. Tillsätt buljongen, ingefäran och pressad limesaft. Koka upp och låt småkoka under lock ca 15 minuter tills morötterna är mjuka.","Jordnötshack: hacka och blanda jordnötter och koriander grovt.","Ta soppan från värmen. Mixa den slät med stavmixer eller matberedare. Tillsätt kokosmjölken och värm upp soppan. Smaka av med sambal oelek, salt och peppar.","Servera soppan med jordnötshack och bröd."]}');
